import { CompletionItemKind, CompletionItem } from "vscode-languageserver";

function getVSCodeCompletionItemKind(
  completionItem: Kusto.Language.Editor.CompletionItem,
): CompletionItemKind {
  // Defensive check for null/undefined completionItem or missing Kind property
  if (!completionItem || completionItem.Kind === null || completionItem.Kind === undefined) {
    return CompletionItemKind.Text;
  }

  switch (completionItem.Kind) {
    case Kusto.Language.Editor.CompletionKind.Cluster:
      return CompletionItemKind.Module;
    case Kusto.Language.Editor.CompletionKind.Database:
      return CompletionItemKind.Class;
    case Kusto.Language.Editor.CompletionKind.Table:
      return CompletionItemKind.Enum;
    case Kusto.Language.Editor.CompletionKind.Column:
      return CompletionItemKind.EnumMember;
    case Kusto.Language.Editor.CompletionKind.BuiltInFunction:
    case Kusto.Language.Editor.CompletionKind.LocalFunction:
    case Kusto.Language.Editor.CompletionKind.DatabaseFunction:
    case Kusto.Language.Editor.CompletionKind.AggregateFunction:
      return CompletionItemKind.Function;
    case Kusto.Language.Editor.CompletionKind.Parameter:
      return CompletionItemKind.TypeParameter;
    case Kusto.Language.Editor.CompletionKind.Variable:
    case Kusto.Language.Editor.CompletionKind.Identifier:
      return CompletionItemKind.Variable;
    case Kusto.Language.Editor.CompletionKind.Syntax:
    case Kusto.Language.Editor.CompletionKind.Keyword:
    case Kusto.Language.Editor.CompletionKind.ScalarPrefix:
    case Kusto.Language.Editor.CompletionKind.TabularPrefix:
    case Kusto.Language.Editor.CompletionKind.TabularSuffix:
    case Kusto.Language.Editor.CompletionKind.QueryPrefix:
    case Kusto.Language.Editor.CompletionKind.ScalarInfix:
      return CompletionItemKind.Keyword;
    case Kusto.Language.Editor.CompletionKind.Punctuation:
    case Kusto.Language.Editor.CompletionKind.RenderChart:
    case Kusto.Language.Editor.CompletionKind.Unknown:
    default:
      return CompletionItemKind.Text;
  }
}

function getCompletionItemsAtPosition(
  kustoCodeScript: Kusto.Language.Editor.CodeScript,
  line: number,
  character: number,
): System.Collections.Generic.IReadOnlyList$1<Kusto.Language.Editor.CompletionItem> | null {
  const position = { v: -1 };
  const positionValid = kustoCodeScript.TryGetTextPosition(
    line,
    character,
    position,
  );
  if (!positionValid) {
    throw new Error(
      `Position (${line},${character}) not valid, cannot get completion items`,
    );
  }
  const kustoCodeBlock = kustoCodeScript.GetBlockAtPosition(position.v);
  if (!kustoCodeBlock || !kustoCodeBlock.Service) {
    throw new Error(
      `Code block at position (${line},${character}) not valid, cannot get completion items`,
    );
  }

  const completionItems = kustoCodeBlock.Service.GetCompletionItems(position.v);
  if (!completionItems) {
    throw new Error(
      `Completion items at position (${line},${character}) not valid, cannot get completion items`,
    );
  }

  return completionItems.Items;
}

export function getVSCodeCompletionItemsAtPosition(
  kustoCodeScript: Kusto.Language.Editor.CodeScript,
  line: number,
  character: number,
): CompletionItem[] {
  const completionItems = getCompletionItemsAtPosition(
    kustoCodeScript,
    line,
    character,
  );
  if (!completionItems || !completionItems.Count) {
    return [];
  }

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const vsCodeCompletionItems: CompletionItem[] = (Bridge as any)
    .toArray(completionItems)
    .map((completionItem: Kusto.Language.Editor.CompletionItem) => {
      // Add null-safety check for completionItem
      if (!completionItem) {
        return null;
      }
      return {
        label: completionItem.DisplayText || "",
        kind: getVSCodeCompletionItemKind(completionItem),
      };
    })
    .filter((item: CompletionItem | null): item is CompletionItem => item !== null);
  return vsCodeCompletionItems;
}

import {
  Client as KustoClient,
  KustoConnectionStringBuilder,
} from "azure-kusto-data";

export interface TokenResponse {
  verificationUrl: string;
  userCode: string;
}

// Resource string to kusto client. The azure-kusto-data package
// does not have typescript support.
// eslint-disable-next-line @typescript-eslint/no-explicit-any
const clients: Map<string, any> = new Map();

export function getClient(
  clusterUri: string,
  tenantId: string | undefined,
  authCallback: (tokenResponse: TokenResponse) => void,
) {
  if (clients.has(clusterUri)) {
    return clients.get(clusterUri);
  }
  // If tenant id is empty in the input, consider it undefined when building the connection string
  let actualTenantId = tenantId;
  if (!actualTenantId) {
    actualTenantId = undefined;
  }

  const kcsb = KustoConnectionStringBuilder.withAadDeviceAuthentication(
    clusterUri,
    actualTenantId,
    (deviceCodeInfo) => {
      authCallback({
        verificationUrl: deviceCodeInfo.verificationUri,
        userCode: deviceCodeInfo.userCode,
      });
    },
  );
  const kustoClient = new KustoClient(kcsb);
  clients.set(clusterUri, kustoClient);
  return kustoClient;
}

export function getFirstOrDefaultClient(): {
  clusterUri: string;
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  kustoClient: any;
} {
  if (clients.size > 0) {
    const key = clients.keys().next().value;
    return {
      clusterUri: key,
      kustoClient: clients.get(clients.keys().next().value),
    };
  }
  return {
    clusterUri: "none",
    kustoClient: null,
  };
}

// for future crossplat support
const NEWLINE: string = "\r\n";
const NEWLINE_REGEX: RegExp = /\r\n/g;

function formatBlock(
  block: Kusto.Language.Editor.CodeBlock,
  hasSeenFirstQueryBlockParam: boolean,
  indentSizeParam: number,
): {
  formattedText: string;
  hasSeenFirstQueryBlock: boolean;
  indentSize: number;
} | null {
  if (!block.Service) {
    return null;
  }

  const formattedTextObject = block.Service.GetFormattedText();
  if (!formattedTextObject || !formattedTextObject.Text) {
    return null;
  }

  const formattedText = formattedTextObject.Text;
  let actualHasSeenFirstQueryBlock = hasSeenFirstQueryBlockParam;
  let actualIndentSize = indentSizeParam;

  if (block.Kind === "Query") {
    // Read the indent size from the first query block in the document
    if (!actualHasSeenFirstQueryBlock) {
      actualIndentSize = formattedText.length - formattedText.trimLeft().length;
      actualHasSeenFirstQueryBlock = true;
    }
    // Add the indent to all lines
    let indentedText: string = (
      " ".repeat(actualIndentSize) + formattedText.trimLeft()
    )
      .replace(NEWLINE_REGEX, NEWLINE + " ".repeat(actualIndentSize))
      .trimRight()
      .concat(NEWLINE, NEWLINE);
    // except the final } of a function
    if (indentedText.trim() === "}") {
      indentedText = indentedText.trim();
    }
    if (indentedText.endsWith("\r\n")) {
      const withoutFinalWhitespace: string = indentedText.substring(
        0,
        indentedText.lastIndexOf(NEWLINE) + NEWLINE.length,
      );
      return {
        formattedText: withoutFinalWhitespace,
        hasSeenFirstQueryBlock: actualHasSeenFirstQueryBlock,
        indentSize: actualIndentSize,
      };
    }
    return {
      formattedText: indentedText,
      hasSeenFirstQueryBlock: actualHasSeenFirstQueryBlock,
      indentSize: actualIndentSize,
    };
  }
  return {
    formattedText,
    hasSeenFirstQueryBlock: actualHasSeenFirstQueryBlock,
    indentSize: actualIndentSize,
  };
}

export function formatCodeScript(
  kustoCodeScript: Kusto.Language.Editor.CodeScript,
): string | null {
  const formattedBlocks: string[] = [];

  let formattedText: string = "";
  let hasSeenFirstQueryBlock: boolean = false;
  let indentSize: number = 0;
  const blocks = kustoCodeScript.Blocks;
  if (!blocks) {
    return null;
  }

  for (let i = 0; i < blocks.Count; i += 1) {
    const block = blocks.getItem(i);
    const formattedBlock = formatBlock(
      block,
      hasSeenFirstQueryBlock,
      indentSize,
    );
    if (!formattedBlock) {
      // eslint-disable-next-line no-continue
      continue;
    }
    ({ formattedText, hasSeenFirstQueryBlock, indentSize } = formattedBlock);
    // Remove empty blocks
    if (/\S/.test(formattedText)) {
      formattedBlocks.push(formattedText);
    }
  }

  return formattedBlocks.join("");
}

import KustoClient from "azure-kusto-data/types/src/client";

interface DatabaseMetadata {
  DatabaseName: string;
  PrettyName: string;
}
interface TableMetadata {
  TableName: string;
  DatabaseName: string;
  Folder: string;
  DocString: string;
}
interface TableSchema {
  TableName: string;
  Schema: string;
  DatabaseName: string;
  Folder: string;
  DocString: string;
}
interface FunctionMetadata {
  Name: string;
  Parameters: string;
  Folder: string;
  DocString: string;
}
interface ColumnInfo {
  Name: string;
  Type: string;
  CslType: string;
}

// Helper functions - defined before export functions that use them

function getTypeSymbol(
  type: string,
): Kusto.Language.Symbols.ScalarSymbol | null {
  // Add null-safety check for type parameter
  if (!type || typeof type !== "string") {
    return null;
  }

  try {
    return Kusto.Language.Symbols.ScalarSymbol.From(type);
  } catch (e) {
    // Gracefully handle errors when parsing type
    // eslint-disable-next-line no-console
    console.error(`Error parsing type symbol: ${type}`, e);
    return null;
  }
}

function getSingleParameter(
  parameter: string,
): Kusto.Language.Symbols.Parameter {
  // Expected Form
  // "param1 : param1type"

  const paramSplit = parameter.split(/[: ]+/).filter((s) => s !== "");

  // Add null-safety checks
  if (!paramSplit || paramSplit.length < 2) {
    // Fallback: create a parameter with unknown type if parsing fails
    const paramName =
      paramSplit && paramSplit.length > 0 ? paramSplit[0] : "unknown";
    return new Kusto.Language.Symbols.Parameter.$ctor2(paramName, null);
  }

  return new Kusto.Language.Symbols.Parameter.$ctor2(
    paramSplit[0],
    getTypeSymbol(paramSplit[1]),
  );
}

function getParameters(parameters: string): Kusto.Language.Symbols.Parameter[] {
  // Expected Form
  // "([param1:param1type][, param2:param2type]...)"
  const params: string[] = parameters
    .substring(1, parameters.length - 1)
    .split(",")
    .filter((s) => s !== "");
  const kParams: Kusto.Language.Symbols.Parameter[] = [];
  params.forEach((param) => kParams.push(getSingleParameter(param)));
  return kParams;
}

function getTableColumns(
  tableSchemas: TableSchema,
): Kusto.Language.Symbols.ColumnSymbol[] {
  const columns: Kusto.Language.Symbols.ColumnSymbol[] = [];
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const schema: any = JSON.parse(tableSchemas.Schema);

  const orderedColumns: ColumnInfo[] = schema.OrderedColumns;

  orderedColumns.forEach((column) => {
    // Add null-safety check for column and type symbol
    if (column && column.Name) {
      const typeSymbol = getTypeSymbol(column.CslType);
      // Only add column if we can determine its type
      if (typeSymbol) {
        columns.push(
          new Kusto.Language.Symbols.ColumnSymbol(
            column.Name,
            typeSymbol,
            null,
            null,
            null,
            null,
          ),
        );
      }
    }
  });

  return columns;
}

/**
 * @param kustoClient a Kusto client from azure-kusto-data
 * @param defaultDatabaseName to run `.show xyz` queries on
 */
// TODO: use this function
// eslint-disable-next-line @typescript-eslint/no-unused-vars
function getDatabasesOnCluster(
  kustoClient: KustoClient,
  defaultDatabaseName: string,
): Promise<DatabaseMetadata[]> {
  return new Promise((resolve, reject) => {
    const databaseNames: { DatabaseName: string; PrettyName: string }[] = [];
    kustoClient
      .execute(defaultDatabaseName, ".show cluster databases")
      .catch(reject)
      .then((results) => {
        if (!results) {
          return reject(new Error("void results"));
        }

        // eslint-disable-next-line no-console
        console.log(results);
        if (!results.primaryResults || !results.primaryResults[0]) {
          return reject(new Error("Failed to fetch databases in cluster"));
        }
        const primaryResults = results.primaryResults[0];
        // eslint-disable-next-line no-underscore-dangle
        for (let i = 0; i < primaryResults._rows.length; i += 1) {
          databaseNames.push({
            // eslint-disable-next-line no-underscore-dangle
            DatabaseName: primaryResults._rows[i].DatabaseName,
            // eslint-disable-next-line no-underscore-dangle
            PrettyName: primaryResults._rows[i].PrettyName,
          });
        }
        return resolve(databaseNames);
      });
  });
}

/**
 * https://kusto.azurewebsites.net/docs/management/functions.html#show-functions
 * NameStringThe name of the function.
 * ParametersStringThe parameters that are required by the function.
 * BodyString(Zero or more) Let statements followed by a valid CSL expression that is evaluated upon function invocation.
 * FolderStringA folder that is used for UI functions categorization. This parameter does not change the way function is invoked
 * DocStringStringA description of the function - to be shown for UI purposes.
 * @param kustoClient
 * @param defaultDatabaseName
 */
function getFunctionMetadata(
  kustoClient: KustoClient,
  databaseName: string,
): Promise<FunctionMetadata[]> {
  return new Promise((resolve, reject) => {
    const functionMetadatas: {
      Name: string;
      Parameters: string;
      Folder: string;
      DocString: string;
    }[] = [];
    kustoClient
      .execute(databaseName, ".show functions")
      .catch(reject)
      .then((results) => {
        if (!results) {
          return reject(new Error("void results"));
        }

        // eslint-disable-next-line no-console
        console.log(results);
        if (!results.primaryResults || !results.primaryResults[0]) {
          return reject(new Error("Failed to fetch functions in cluster"));
        }
        const primaryResults = results.primaryResults[0];
        // eslint-disable-next-line no-underscore-dangle
        for (let i = 0; i < primaryResults._rows.length; i += 1) {
          functionMetadatas.push({
            // eslint-disable-next-line no-underscore-dangle
            Name: primaryResults._rows[i].Name,
            // eslint-disable-next-line no-underscore-dangle
            Parameters: primaryResults._rows[i].Parameters,
            // eslint-disable-next-line no-underscore-dangle
            Folder: primaryResults._rows[i].Folder,
            // eslint-disable-next-line no-underscore-dangle
            DocString: primaryResults._rows[i].DocString,
          });
        }
        return resolve(functionMetadatas);
      });
  });
}

/**
 * https://kusto.azurewebsites.net/docs/management/tables.html#show-tables
 * TableNameStringThe name of the table.
 * DatabaseNameStringThe database that the table belongs to.
 * FolderStringThe table's folder.
 * DocStringStringA string documenting the table.
 *
 * TODO for each, get schema: .show table schema https://kusto.azurewebsites.net/docs/management/tables.html#show-tables
 * @param kustoClient
 * @param databaseName
 */
function getTableMetadata(
  kustoClient: KustoClient,
  databaseName: string,
): Promise<TableMetadata[]> {
  return new Promise((resolve, reject) => {
    const tableMetadatas: {
      TableName: string;
      DatabaseName: string;
      Folder: string;
      DocString: string;
    }[] = [];
    kustoClient
      .execute(databaseName, ".show tables")
      .catch(reject)
      .then((results) => {
        if (!results) {
          return reject(new Error("void results"));
        }

        // eslint-disable-next-line no-console
        console.log(results);
        if (!results.primaryResults || !results.primaryResults[0]) {
          return reject(new Error("Failed to fetch tables in cluster"));
        }
        const primaryResults = results.primaryResults[0];
        // eslint-disable-next-line no-underscore-dangle
        for (let i = 0; i < primaryResults._rows.length; i += 1) {
          tableMetadatas.push({
            // eslint-disable-next-line no-underscore-dangle
            TableName: primaryResults._rows[i].TableName,
            // eslint-disable-next-line no-underscore-dangle
            DatabaseName: primaryResults._rows[i].DatabaseName,
            // eslint-disable-next-line no-underscore-dangle
            Folder: primaryResults._rows[i].Folder,
            // eslint-disable-next-line no-underscore-dangle
            DocString: primaryResults._rows[i].DocString,
          });
        }
        return resolve(tableMetadatas);
      });
  });
}

function getTableSchema(
  kustoClient: KustoClient,
  databaseName: string,
  tableName: string,
): Promise<TableSchema> {
  return new Promise((resolve, reject) => {
    kustoClient
      .execute(databaseName, `.show table ${tableName} schema as json`)
      .catch(reject)
      .then((results) => {
        if (!results) {
          return reject(new Error("void results"));
        }

        // eslint-disable-next-line no-console
        console.log(results);
        if (!results.primaryResults || !results.primaryResults[0]) {
          return reject(new Error("Failed to fetch tables in cluster"));
        }
        const primaryResults = results.primaryResults[0];

        // eslint-disable-next-line no-underscore-dangle
        const tableMetadata = {
          // eslint-disable-next-line no-underscore-dangle
          TableName: primaryResults._rows[0].TableName,
          // eslint-disable-next-line no-underscore-dangle
          Schema: primaryResults._rows[0].Schema,
          // eslint-disable-next-line no-underscore-dangle
          DatabaseName: primaryResults._rows[0].DatabaseName,
          // eslint-disable-next-line no-underscore-dangle
          Folder: primaryResults._rows[0].Folder,
          // eslint-disable-next-line no-underscore-dangle
          DocString: primaryResults._rows[0].DocString,
        };

        return resolve(tableMetadata);
      });
  });
}

function getTableSymbols(
  metadata: TableMetadata[],
): Kusto.Language.Symbols.TableSymbol[] {
  const symbols: Kusto.Language.Symbols.TableSymbol[] = [];
  // eslint-disable-next-line no-restricted-syntax
  for (const m of metadata) {
    symbols.push(
      new Kusto.Language.Symbols.TableSymbol.$ctor4(m.TableName, []),
    );
  }
  return symbols;
}

function getFunctionSymbols(
  metadata: FunctionMetadata[],
  // TODO: use globalState to get return type, signature types, etc of the functions
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  globalState: Kusto.Language.GlobalState,
): Array<Kusto.Language.Symbols.FunctionSymbol> {
  const symbols: Kusto.Language.Symbols.FunctionSymbol[] = [];

  // eslint-disable-next-line no-restricted-syntax
  for (const m of metadata) {
    // TODO return type, signature types etc. Will require additional calls to cluster.
    const signature = new Kusto.Language.Symbols.Signature.$ctor2(
      Kusto.Language.Symbols.ReturnTypeKind.Common,
      getParameters(m.Parameters),
    );
    symbols.push(
      new Kusto.Language.Symbols.FunctionSymbol.$ctor4(m.Name, [signature]),
    );
  }

  return symbols;
}

// Exported functions - these depend on helpers above

export async function getSymbolsOnCluster(
  kustoClient: KustoClient,
  defaultDatabaseName: string,
): Promise<Kusto.Language.GlobalState | null> {
  // TODO use this functionality
  // const databasesMetadata = await getDatabasesOnCluster(kustoClient, defaultDatabaseName);
  // for (let databaseNames of databasesMetadata) {
  // const functionMetadatas = await getFunctionsOnDatabase(kustoClient, defaultDatabaseName);
  // }
  // for (let databaseNames of databasesMetadata) {
  // const tableMetadatas = await getTablesOnDatabase(kustoClient, defaultDatabaseName);
  // }
  const tableMetadata = await getTableMetadata(
    kustoClient,
    defaultDatabaseName,
  );
  const functionMetadata = await getFunctionMetadata(
    kustoClient,
    defaultDatabaseName,
  );
  const globalState = Kusto.Language.GlobalState.Default;
  if (!globalState) {
    return null;
  }
  const symbols = [];
  symbols.push(...getTableSymbols(tableMetadata));
  symbols.push(...getFunctionSymbols(functionMetadata, globalState));
  return globalState.WithDatabase(
// eslint-disable-next-line new-cap
    new Kusto.Language.Symbols.DatabaseSymbol.ctor(
      defaultDatabaseName,
      symbols,
    ),
  );
}

export async function getSymbolsOnTable(
  kustoClient: KustoClient,
  defaultDatabaseName: string,
  tableName: string,
  globalState: Kusto.Language.GlobalState,
): Promise<Kusto.Language.GlobalState | null> {
  const tableSchema = await getTableSchema(
    kustoClient,
    defaultDatabaseName,
    tableName,
  );
  const columns = getTableColumns(tableSchema);
  const newTable = new Kusto.Language.Symbols.TableSymbol.$ctor4(
    tableName,
    columns,
  );
  if (!globalState.Database) {
    return null;
  }
  return globalState.WithDatabase(globalState.Database.AddMembers([newTable]));
}

import "@kusto/language-service-next/bridge";
import "@kusto/language-service-next/Kusto.Language.Bridge";

import {
  createConnection,
  TextDocuments,
  Diagnostic,
  DiagnosticSeverity,
  ProposedFeatures,
  InitializeParams,
  DidChangeConfigurationNotification,
  CompletionItem,
  TextDocumentPositionParams,
  Hover,
  TextEdit,
  DocumentFormattingParams,
  TextDocumentSyncKind,
} from "vscode-languageserver/node";
import { TextDocument } from "vscode-languageserver-textdocument";

import {
  getClient as getKustoClient,
  TokenResponse,
  getFirstOrDefaultClient,
} from "./kustoConnection";
import { getSymbolsOnCluster, getSymbolsOnTable } from "./kustoSymbols";
import { formatCodeScript } from "./kustoFormat";
import { getVSCodeCompletionItemsAtPosition } from "./kustoCompletion";

// Create a connection for the server. The connection uses Node's IPC as a transport.
// Also include all preview / proposed LSP features.
const connection = createConnection(ProposedFeatures.all);

// Create a simple text document manager. The text document manager
// supports full document sync only
const documents = new TextDocuments(TextDocument);

// Create a collection of Kusto code services, one for each document
type documentURI = string;
let kustoGlobalState = Kusto.Language.GlobalState.Default;
const kustoCodeScripts: Map<
  documentURI,
  Kusto.Language.Editor.CodeScript | null
> = new Map();

let hasConfigurationCapability: boolean = false;
let hasWorkspaceFolderCapability: boolean = false;
let hasDiagnosticRelatedInformationCapability: boolean = false;

connection.onInitialize((params: InitializeParams) => {
  const {capabilities} = params;

  // Does the client support the `workspace/configuration` request?
  // If not, we will fall back using global settings
  hasConfigurationCapability = !!(
    capabilities.workspace && !!capabilities.workspace.configuration
  );

  hasWorkspaceFolderCapability = !!(
    capabilities.workspace && !!capabilities.workspace.workspaceFolders
  );
  hasDiagnosticRelatedInformationCapability = !!(
    capabilities.textDocument &&
    capabilities.textDocument.publishDiagnostics &&
    capabilities.textDocument.publishDiagnostics.relatedInformation
  );

  return {
    capabilities: {
      textDocumentSync: TextDocumentSyncKind.Full,
      completionProvider: {
        resolveProvider: true,
      },
      hoverProvider: true,
      documentFormattingProvider: true,
    },
  };
});

connection.onInitialized(async () => {
  if (hasConfigurationCapability) {
    // Register for all configuration changes.
    connection.client.register(
      DidChangeConfigurationNotification.type,
      undefined,
    );
  }
  if (hasWorkspaceFolderCapability) {
    connection.workspace.onDidChangeWorkspaceFolders((_event) => {
      connection.console.log(
        `Workspace folder change event received. ${_event.added.length} added, ${_event.removed.length} removed`,
      );
    });
  }
  if (hasDiagnosticRelatedInformationCapability) {
    // TODO: support diagnostics
  }
});

connection.onRequest(
  "kuskus.loadSymbols",
  async ({
    clusterUri,
    tenantId,
    database,
  }: {
    clusterUri: string;
    tenantId: string | undefined;
    database: string;
  }) => {
    const kustoClient = getKustoClient(
      clusterUri,
      tenantId,
      (tokenResponse: TokenResponse) => {
        connection.sendRequest("kuskus.loadSymbols.auth", {
          clusterUri,
          tenantId,
          database,
          verificationUrl: tokenResponse.verificationUrl,
          verificationCode: tokenResponse.userCode,
        });
      },
    );

    try {
      kustoGlobalState = await getSymbolsOnCluster(kustoClient, database);
      connection.sendNotification("kuskus.loadSymbols.auth.complete.success", {
        clusterUri,
        tenantId,
        database,
      });
      connection.sendNotification("kuskus.loadSymbols.success", {
        clusterUri,
        database,
      });
      kustoCodeScripts.forEach((value, key) => {
        if (value) {
          kustoCodeScripts.set(key, value.WithGlobals(kustoGlobalState));
        }
      });
    } catch (e) {
      let errorMessage = "unknown";
      if (e instanceof Error) {
